args.query:
SELECT COALESCE(newvalue__c, oldvalue__c) AS agent_id
FROM casehistory__c
WHERE field__c = 'Owner' AND createddate >= '2022-04-10' AND createddate < '2023-04-11' AND (newvalue__c IS NOT NULL OR oldvalue__c IS NOT NULL);

